```c
#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int *data;
    size_t size;
    size_t capacity;
} Vec;

Vec vec_new(void) {
    Vec v;
    v.data = malloc(4 * sizeof(int));
    v.size = 0;
    v.capacity = 4;
    return v;
}

void vec_push(Vec *v, int value) {
    if (v->size == v->capacity) {
        v->capacity *= 2;
        int *tmp = realloc(v->data, v->capacity * sizeof(int));
        if (!tmp) { fprintf(stderr, "OOM\n"); exit(1); }
        v->data = tmp;
    }
    v->data[v->size++] = value;
}

void vec_free(Vec *v) {
    free(v->data);
    v->data = NULL;
    v->size = v->capacity = 0;
}
```

