```c
#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node *next;
} Node;

Node *list_prepend(Node *head, int data) {
    Node *n = malloc(sizeof(Node));
    n->data = data;
    n->next = head;
    return n;
}

Node *list_append(Node *head, int data) {
    Node *n = malloc(sizeof(Node));
    n->data = data;
    n->next = NULL;
    if (!head) return n;
    Node *cur = head;
    while (cur->next) cur = cur->next;
    cur->next = n;
    return head;
}

Node *list_remove(Node *head, int target) {
    if (!head) return NULL;
    if (head->data == target) {
        Node *tmp = head->next;
        free(head);
        return tmp;
    }
    Node *cur = head;
    while (cur->next && cur->next->data != target)
        cur = cur->next;
    if (cur->next) {
        Node *tmp = cur->next;
        cur->next = tmp->next;
        free(tmp);
    }
    return head;
}

void list_free(Node *head) {
    while (head) {
        Node *tmp = head->next;
        free(head);
        head = tmp;
    }
}
```

