```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct { char *data; int top; int cap; } Stack;
Stack stack_new(int cap) {
    Stack s; s.data = malloc(cap); s.top = -1; s.cap = cap; return s;
}
void stack_push(Stack *s, char c) { s->data[++s->top] = c; }
char stack_pop(Stack *s) { return s->data[s->top--]; }
int stack_empty(Stack *s) { return s->top < 0; }
char stack_peek(Stack *s) { return s->data[s->top]; }

int is_match(char a, char b) {
    return (a=='('&&b==')') || (a=='['&&b==']') || (a=='{'&&b=='}');
}

int check(const char *s) {
    Stack st = stack_new(strlen(s));
    for (int i = 0; s[i]; i++) {
        if (s[i]=='('||s[i]=='['||s[i]=='{') stack_push(&st, s[i]);
        else if (s[i]==')'||s[i]==']'||s[i]=='}') {
            if (stack_empty(&st) || !is_match(stack_peek(&st), s[i])) return 0;
            stack_pop(&st);
        }
    }
    return stack_empty(&st);
}
```

**算法：** 左括号入栈，右括号检查栈顶是否匹配。三种不匹配：右括号与栈顶不配、栈空遇右括号、结束后栈非空。

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define TABLE_SIZE 64

typedef struct Entry {
    char *key;
    int value;
    struct Entry *next;
} Entry;

typedef struct { Entry *buckets[TABLE_SIZE]; } HashTable;

unsigned long hash(const char *s) {
    unsigned long h = 5381;
    while (*s) h = h * 33 + *s++;
    return h % TABLE_SIZE;
}

HashTable *ht_new(void) { return calloc(1, sizeof(HashTable)); }

void ht_set(HashTable *ht, const char *key, int val) {
    unsigned long idx = hash(key);
    Entry *e = ht->buckets[idx];
    while (e) {
        if (strcmp(e->key, key) == 0) { e->value = val; return; }
        e = e->next;
    }
    Entry *n = malloc(sizeof(Entry));
    n->key = strdup(key);
    n->value = val;
    n->next = ht->buckets[idx];
    ht->buckets[idx] = n;
}

int ht_get(HashTable *ht, const char *key, int *out) {
    Entry *e = ht->buckets[hash(key)];
    while (e) {
        if (strcmp(e->key, key) == 0) { *out = e->value; return 1; }
        e = e->next;
    }
    return 0;
}
```

**设计：** djb2哈希 + 链地址法。`ht_get` 返回bool区分"key不存在"和"值为0"。

```c
void bubble_sort(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        int swapped = 0;
        for (int j = 0; j < n - 1 - i; j++) {
            if (arr[j] > arr[j + 1]) {
                int tmp = arr[j]; arr[j] = arr[j+1]; arr[j+1] = tmp;
                swapped = 1;
            }
        }
        if (!swapped) break;
    }
}
```

**要点：** `swapped` 优化——某轮无交换则提前终止；时间O(n²)，最好O(n)（已有序）；空间O(1)。实际项目优先用 `qsort`。

```c
void swap(int *a, int *b) { int t = *a; *a = *b; *b = t; }

int partition(int arr[], int low, int high) {
    int pivot = arr[high];
    int i = low;
    for (int j = low; j < high; j++)
        if (arr[j] <= pivot) swap(&arr[i++], &arr[j]);
    swap(&arr[i], &arr[high]);
    return i;
}

void quick_sort(int arr[], int low, int high) {
    if (low < high) {
        int pi = partition(arr, low, high);
        quick_sort(arr, low, pi - 1);
        quick_sort(arr, pi + 1, high);
    }
}
```

**要点：** 选最后一个元素为pivot；平均O(n log n)，最坏O(n²)；实际项目用 `qsort`。

