```c
#include <stdlib.h>
#include <string.h>

void merge(int arr[], int l, int m, int r) {
    int n1 = m - l + 1, n2 = r - m;
    int *L = malloc(n1 * sizeof(int)), *R = malloc(n2 * sizeof(int));
    memcpy(L, arr + l, n1 * sizeof(int));
    memcpy(R, arr + m + 1, n2 * sizeof(int));
    int i = 0, j = 0, k = l;
    while (i < n1 && j < n2)
        arr[k++] = L[i] <= R[j] ? L[i++] : R[j++];
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
    free(L); free(R);
}

void merge_sort(int arr[], int l, int r) {
    if (l < r) {
        int m = l + (r - l) / 2;
        merge_sort(arr, l, m);
        merge_sort(arr, m + 1, r);
        merge(arr, l, m, r);
    }
}
```

**要点：** 稳定排序；时间O(n log n)，空间O(n)；适合链表排序和外部排序。

```c
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node *left, *right;
} Node;

Node *bst_insert(Node *root, int val) {
    if (!root) {
        Node *n = calloc(1, sizeof(Node));
        n->val = val;
        return n;
    }
    if (val < root->val) root->left = bst_insert(root->left, val);
    else if (val > root->val) root->right = bst_insert(root->right, val);
    return root;
}

Node *bst_search(Node *root, int val) {
    if (!root || root->val == val) return root;
    return val < root->val ? bst_search(root->left, val) : bst_search(root->right, val);
}

Node *bst_min(Node *root) {
    while (root && root->left) root = root->left;
    return root;
}

Node *bst_delete(Node *root, int val) {
    if (!root) return NULL;
    if (val < root->val) root->left = bst_delete(root->left, val);
    else if (val > root->val) root->right = bst_delete(root->right, val);
    else {
        if (!root->left) { Node *r = root->right; free(root); return r; }
        if (!root->right) { Node *r = root->left; free(root); return r; }
        Node *succ = bst_min(root->right);
        root->val = succ->val;
        root->right = bst_delete(root->right, succ->val);
    }
    return root;
}
```

