```c
#include <stdlib.h>

typedef struct Node { int data; struct Node *next; } Node;

typedef struct {
    Node *head;
    Node *tail;
    int size;
} Queue;

Queue queue_new(void) { return (Queue){NULL, NULL, 0}; }

void queue_push(Queue *q, int val) {
    Node *n = malloc(sizeof(Node));
    n->data = val;
    n->next = NULL;
    if (q->tail) q->tail->next = n;
    else q->head = n;
    q->tail = n;
    q->size++;
}

int queue_pop(Queue *q) {
    if (!q->head) return -1;
    Node *tmp = q->head;
    int val = tmp->data;
    q->head = tmp->next;
    if (!q->head) q->tail = NULL;
    free(tmp);
    q->size--;
    return val;
}

int queue_empty(Queue *q) { return q->size == 0; }
