用 `void*` + 函数指针 + 元素大小：

```c
#include <string.h>

void swap_generic(void *a, void *b, size_t size) {
    char tmp[256];
    if (size > sizeof(tmp)) return;
    memcpy(tmp, a, size);
    memcpy(a, b, size);
    memcpy(b, tmp, size);
}

void my_qsort(void *base, size_t n, size_t size,
              int (*cmp)(const void *, const void *)) {
    if (n <= 1) return;
    char *arr = base;
    char *pivot = arr + (n-1) * size;
    size_t i = 0;
    for (size_t j = 0; j < n-1; j++)
        if (cmp(arr + j*size, pivot) <= 0)
            swap_generic(arr + i*size, arr + j*size, size), i++;
    swap_generic(arr + i*size, pivot, size);
    my_qsort(arr, i, size, cmp);
    my_qsort(arr + (i+1)*size, n-i-1, size, cmp);
}
```

**关键技术：** `(char *)base + i * size` 计算第i个元素地址；`memcpy` 代替赋值；比较函数指针由调用者提供。比较函数不要用减法，可能溢出。

```c
#include <stdlib.h>
#include <stdint.h>

typedef struct {
    uint8_t *buffer;
    size_t block_size;
    size_t free_count;
    void *free_list;
} MemPool;

MemPool pool_create(size_t block_size, size_t count) {
    MemPool p;
    p.block_size = block_size < sizeof(void*) ? sizeof(void*) : block_size;
    p.free_count = count;
    p.buffer = malloc(p.block_size * count);
    p.free_list = p.buffer;
    uint8_t *blk = p.buffer;
    for (size_t i = 0; i < count - 1; i++) {
        *(void**)blk = blk + p.block_size;
        blk += p.block_size;
    }
    *(void**)blk = NULL;
    return p;
}

void *pool_alloc(MemPool *p) {
    if (!p->free_count) return NULL;
    void *blk = p->free_list;
    p->free_list = *(void**)blk;
    p->free_count--;
    return blk;
}

void pool_free(MemPool *p, void *blk) {
    *(void**)blk = p->free_list;
    p->free_list = blk;
    p->free_count++;
}
```

**原理：** 预分配连续内存，空闲块用内置链表串起来。分配O(1)，释放O(1)。适用于频繁创建/销毁相同类型对象。

```c
void insertion_sort(int arr[], int n) {
    for (int i = 1; i < n; i++) {
        int key = arr[i];
        int j = i - 1;
        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
}
