```c
void selection_sort(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        int min_idx = i;
        for (int j = i + 1; j < n; j++)
            if (arr[j] < arr[min_idx]) min_idx = j;
        if (min_idx != i) {
            int tmp = arr[i]; arr[i] = arr[min_idx]; arr[min_idx] = tmp;
        }
    }
}
```

**要点：** 不稳定排序（交换可能改变相等元素顺序）；时间O(n²)，空间O(1)；交换次数最少（最多n-1次）；适合交换代价大的场景。

```c
#define MAX_V 100

typedef struct { int adj[MAX_V][MAX_V]; int v; } Graph;

int visited[MAX_V];

void dfs(Graph *g, int start) {
    visited[start] = 1;
    printf("%d ", start);
    for (int i = 0; i < g->v; i++)
        if (g->adj[start][i] && !visited[i])
            dfs(g, i);
}

void bfs(Graph *g, int start) {
    int queue[MAX_V], front = 0, rear = 0;
    int vis[MAX_V] = {0};
    queue[rear++] = start;
    vis[start] = 1;
    while (front < rear) {
        int cur = queue[front++];
        printf("%d ", cur);
        for (int i = 0; i < g->v; i++)
            if (g->adj[cur][i] && !vis[i]) {
                queue[rear++] = i;
                vis[i] = 1;
            }
    }
}
```

**DFS：** 栈/递归，适合路径搜索、连通性检测。**BFS：** 队列，适合最短路径（无权图）、层序遍历。

```c
int knapsack(int W, int wt[], int val[], int n) {
    int dp[n + 1][W + 1];
    for (int i = 0; i <= n; i++)
        for (int w = 0; w <= W; w++) {
            if (i == 0 || w == 0) dp[i][w] = 0;
            else if (wt[i-1] <= w)
                dp[i][w] = val[i-1] + dp[i-1][w - wt[i-1]] > dp[i-1][w]
                           ? val[i-1] + dp[i-1][w - wt[i-1]] : dp[i-1][w];
            else dp[i][w] = dp[i-1][w];
        }
    return dp[n][W];
}
```

**状态转移：** `dp[i][w]` = 前i个物品、容量w时的最大价值
- 不选物品i：`dp[i-1][w]`
- 选物品i：`val[i-1] + dp[i-1][w-wt[i-1]]`

**空间优化：** 用一维数组逆序遍历：`dp[w] = max(dp[w], val[i]+dp[w-wt[i]])`，O(W)空间。

```c
#include <string.h>

int lcs(const char *s1, const char *s2) {
    int m = strlen(s1), n = strlen(s2);
    int dp[m + 1][n + 1];
    for (int i = 0; i <= m; i++)
        for (int j = 0; j <= n; j++) {
            if (i == 0 || j == 0) dp[i][j] = 0;
            else if (s1[i-1] == s2[j-1]) dp[i][j] = dp[i-1][j-1] + 1;
            else dp[i][j] = dp[i-1][j] > dp[i][j-1] ? dp[i-1][j] : dp[i][j-1];
        }
    return dp[m][n];
}
```

**状态转移：** 字符相同→`dp[i-1][j-1]+1`；不同→`max(dp[i-1][j], dp[i][j-1])`

**回溯路径：** 从 `dp[m][n]` 往回走，相同字符加入结果。时间O(mn)，空间可优化到O(min(m,n))。

双指针用两个索引/指针协同遍历，将O(n²)降为O(n)：

**1. 对撞指针（有序数组两数之和）**
```c
int *two_sum(int *arr, int n, int target) {
    int left = 0, right = n - 1;
    static int result[2];
    while (left < right) {
        int sum = arr[left] + arr[right];
        if (sum == target) { result[0]=left; result[1]=right; return result; }
        else if (sum < target) left++;
        else right--;
    }
    return NULL;
}
```

**2. 快慢指针（找链表中点/环检测）**
```c
int has_cycle(Node *head) {
    Node *slow = head, *fast = head;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast) return 1;
    }
    return 0;
}
```

**3. 滑动窗口（最长无重复子串）**：右指针扩展，左指针收缩。

```c
#include <stdio.h>
#include <stdlib.h>

int solve_nq(int n) {
    int *cols = calloc(n, sizeof(int));
    int count = 0;
    void backtrack(int row) {
        if (row == n) { count++; return; }
        for (int col = 0; col < n; col++) {
            int ok = 1;
            for (int r = 0; r < row; r++)
                if (cols[r] == col || abs(cols[r]-col) == abs(r-row))
                    { ok = 0; break; }
            if (ok) { cols[row] = col; backtrack(row + 1); }
        }
    }
    backtrack(0);
    free(cols);
    return count;
}
```

**回溯三步：** 选择→递归→撤销。冲突检测：同列 `cols[r]==col`；对角线 `|cols[r]-col|==|r-row|`。

**时间：** O(n!)，n=8时92个解。

```c
typedef struct TreeNode {
    int val;
