如果需要更高效率（多次查找），可用**KMP算法**：
```c
void build_lps(const char *pat, int *lps, int m) {
    int len = 0; lps[0] = 0;
    int i = 1;
    while (i < m) {
        if (pat[i] == pat[len]) lps[i++] = ++len;
        else if (len) len = lps[len - 1];
        else lps[i++] = 0;
    }
}

int kmp_search(const char *txt, const char *pat) {
    int n = strlen(txt), m = strlen(pat);
    int *lps = malloc(m * sizeof(int));
    build_lps(pat, lps, m);
    int i = 0, j = 0;
    while (i < n) {
        if (txt[i] == pat[j]) { i++; j++; }
        if (j == m) { free(lps); return i - j; }
        else if (i < n && txt[i] != pat[j]) {
            if (j) j = lps[j-1]; else i++;
        }
    }
    free(lps); return -1;
}
```

**KMP核心：** LPS数组避免重复比较，O(n+m)时间。

