根据参考文档，实现一个简单的 key=value 配置解析器：

```c
#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <ctype.h>

typedef struct { char key[64]; char value[256]; } ConfigEntry;

static char *trim(char *s) {
    while (isspace(*s)) s++;
    char *end = s + strlen(s) - 1;
    while (end > s && isspace(*end)) *end-- = '\0';
    return s;
}

int parse_config(const char *path, ConfigEntry *entries, int max) {
    FILE *fp = fopen(path, "r");
    if (!fp) return -1;
    int count = 0;
    char line[512];
    while (fgets(line, sizeof(line), fp) && count < max) {
        char *p = trim(line);
        if (*p == '#' || *p == '\0') continue;
        char *eq = strchr(p, '=');
        if (!eq) continue;
        *eq = '\0';
        strncpy(entries[count].key, trim(p), 63);
        strncpy(entries[count].value, trim(eq + 1), 255);
        count++;
    }
    fclose(fp);
    return count;
}
```

**支持格式：** `key = value`、`#注释`、自动去除空白。
